import math
import Lean
import Mathlib
import Main
import YourHelper
import YourModule

def verify(w: unsigned int) (is_divisible1: bool) (is_divisible2: bool) (overflow: bool) {
  if (overflow) {
    return false;
  }
  if (is_divisible1 != is_divisible2) {
    return false;
  }
  return true;
}

def main(w: unsigned int) {
  let result: bool = verify(w);
  return result;
}

def correct_version(w: unsigned int) {
  if (w < 4) {
    return false;
  }
  else {
    let i: int = 0;
    while (i < w) {
      let j: int = i + 2;
      if (j >= w) {
        return false;
      }
      i = j;
    }
    return true;
  }
}

def student_version(w: unsigned int) {
  let i: int = 0;
  while (i < w) {
    let j: int = i + 2;
    if (j >= w) {
      return false;
    }
    i = j;
  }
  return true;
}

theorem property {
  let w: unsigned int = __VERIFIER_nondet_uint();
  let is_divisible1: bool = true;
  let is_divisible2: bool = true;
  let overflow: bool = false;

  -- Verify that the correctness functions are correct and that the overflow condition holds.
  check
  (fun w is_divisible1 is_divisible2 overflow => {
    check
    (fun _ is_divisible1 is_divisible2 overflow => {
      if (overflow) {
        check (fun w => verify w (is_divisible1) (is_divisible2) overflow)
          (fun w => verify w (is_divisible1) (is_divisible2) overflow)
          (fun _ => false)
        })
      else {
        check
          (fun _ is_divisible1 is_divisible2 overflow => {
            if (is_divisible1 != is_divisible2) {
              check (fun _ => false)
                (fun _ => true)
                (fun _ => true)
              }
            }
            check (fun _ => true)
              (fun _ => false)
              (fun _ => false)
          })
        }
      }
    })
  )
}
